"""voice-typer 패치 스크립트.

이미 받아서 쓰고 있는 voice-typer 폴더 안에 이 파일을 넣고 실행하면,
config.py / overlay.py / voice_typer.py 3개 파일을 최신 내용으로 덮어쓴다.
"""

import pathlib

HERE = pathlib.Path(__file__).resolve().parent

FILES = {}
FILES['config.py'] = '"""voice-typer 설정 파일. 값만 바꿔서 쓰면 됨."""\n\n# 이 키를 누르면 녹음 시작/종료가 토글됨 (keyboard 라이브러리 키 이름 규칙 사용).\n# F2는 오브시디언 등 여러 앱에서 "제목 바꾸기(rename)"에 쓰이지만, 아래\n# SUPPRESS_HOTKEY가 켜져 있으면 그 앱으로 키 입력이 전달되지 않아서 충돌이\n# 안 생긴다. 그래도 계속 겹치는 앱이 있으면 "scroll lock"이나 "pause"로\n# 바꿔볼 것.\nHOTKEY = "f2"\n\n# True로 두면 HOTKEY를 누르는 순간 그 키 입력 자체가 현재 포커스된 프로그램으로\n# 전달되지 않도록 막는다 (keyboard.add_hotkey의 suppress 옵션). 이렇게 해야\n# 앞으로 어떤 키를 고르든 "그 앱에서도 같은 키에 다른 동작이 매핑되어 있어서\n# 같이 실행돼버리는" 문제가 원천적으로 안 생긴다.\nSUPPRESS_HOTKEY = True\n\n# "toggle": F2로 수동 시작/종료 (기본, 쉬움)\n# "vad":    F2로 "상시 감지 모드"를 켜고 끄기만 하고, 그 안에서는 소리 크기(dB)로 자동 시작/종료\nMODE = "toggle"\n\n# faster-whisper 모델 크기. "turbo" = large-v3-turbo, 속도 우선.\n# 정확도를 더 원하면 "large-v3", 가벼운 GPU(VRAM 부족)면 "medium"/"small"로 낮추면 됨.\nMODEL_SIZE = "turbo"\n\n# "cuda" = GPU 사용 (RTX 3060 이상, VRAM 8GB+ 권장). GPU가 없거나 인식 안 되면 "cpu"로 바꾸되\n# CPU는 turbo 모델도 체감상 많이 느림.\nDEVICE = "cuda"\n\n# GPU float16이 가장 빠르고 8GB VRAM에서도 turbo 모델엔 넉넉함.\n# CPU로 돌릴 때는 "int8"을 추천.\nCOMPUTE_TYPE = "float16"\n\n# 한국어 고정. 다국어 자동감지를 원하면 None으로.\nLANGUAGE = "ko"\n\nSAMPLE_RATE = 16000\n\n# 사용할 마이크를 이름의 일부로 지정 (윈도우 "사운드 설정 > 입력"에 뜨는 이름 참고).\n# 예: "ZenGo" 라고만 써도 이름에 ZenGo가 들어간 장치를 찾아서 씀.\n# None으로 두면 윈도우에 설정된 기본 마이크를 그대로 씀.\nMIC_NAME = "ZenGo"\n\n# ---- MODE = "vad" 일 때만 사용되는 값들 ----\n# 이 dB(대략적인 RMS 기준 dBFS)보다 크게 들리면 "말하는 중"으로 판단.\n# 마이크/환경마다 다르므로 실제로 켜보고 로그에 찍히는 값을 보면서 조정할 것.\nVAD_DB_THRESHOLD = -40\n\n# 말이 끊긴 뒤 이만큼(ms) 조용하면 "한 문장 끝"으로 보고 바로 텍스트 변환 시작.\nVAD_SILENCE_MS = 700\n\n# 녹음 시작 판단을 위해 오디오를 검사하는 블록 길이(ms).\nVAD_BLOCK_MS = 30\n\n# 커서가 있는 곳(현재 포커스된 창)에 실제로 타이핑까지 할지 여부.\n# False로 하면 안전창(safety window)에만 기록되고 실제 타이핑은 안 됨.\nTYPE_AT_CURSOR = True\n\n# 안전창(모든 인식 결과가 항상 남는 별도의 항상-위-창) 크기\nSAFETY_WINDOW_GEOMETRY = "480x320+40+40"\n\n# ---- 녹음 상태 표시등 (화면 구석의 작은 점) ----\n# 안전창을 열어보지 않아도 녹음 중인지 바로 확인할 수 있는 작은 원.\n# 클릭도 그대로 통과시켜서(click-through) 작업에 방해되지 않는다.\nINDICATOR_ENABLED = True\n\n# 화면 어느 구석에 둘지: "bottom-right"(기본), "top-right", "top-left", "bottom-left"\nINDICATOR_CORNER = "bottom-right"\n\nINDICATOR_SIZE = 22       # 지름(px)\n# 화면 가장자리로부터 여백(px). 작업표시줄(taskbar)에 가려지면 이 값을 늘릴 것.\nINDICATOR_MARGIN = 60\n\n# 0.0(완전 투명) ~ 1.0(완전 불투명). 반투명하게 보이려면 1.0보다 낮게.\nINDICATOR_OPACITY = 0.55\n\nINDICATOR_COLOR_IDLE = "#808080"        # 대기 중: 회색\nINDICATOR_COLOR_RECORDING = "#e03131"   # 녹음 중: 빨간색\n'

FILES['overlay.py'] = '"""항상 위에 떠 있는 안전창 + 녹음 상태를 보여주는 작은 표시등.\n\n안전창: 커서가 다른 곳에 없어서 타이핑이 어디에도 들어가지 않았더라도,\n        인식된 텍스트는 전부 이 창에 남는다. 나중에 드래그해서 복사해 쓸 수 있다.\n        최소화해놔도 상관없다.\n\n표시등: 화면 구석에 떠 있는 작은 원. 녹음 중엔 빨간색, 아닐 땐 반투명 회색이\n        되어서 안전창을 열어보지 않아도 녹음 상태를 바로 확인할 수 있다.\n        클릭도 그대로 아래 창으로 통과되게(click-through) 만들어서 작업에\n        방해되지 않는다.\n\n        원형 모양은 Tk의 "-transparentcolor"(컬러키 방식)가 아니라, 윈도우\n        자체를 타원형으로 잘라내는 SetWindowRgn을 쓴다. 컬러키 방식은 Tk/윈도우\n        조합에 따라 안 먹혀서 사각형 검은 박스로 보이는 문제가 있었다.\n        반투명은 "-alpha"(창 전체 투명도)로 처리한다.\n"""\n\nimport queue\nimport sys\nimport threading\nimport time\nimport tkinter as tk\n\nimport config\n\n\ndef _make_click_through(window: tk.Toplevel):\n    """윈도우에서만: 이 창을 클릭이 그대로 통과하는(안 걸리는) 창으로 만든다.\n    실패해도(다른 OS 등) 그냥 무시하고 평범한 창으로 남는다."""\n    if sys.platform != "win32":\n        return\n    try:\n        import ctypes\n\n        GWL_EXSTYLE = -20\n        WS_EX_LAYERED = 0x00080000\n        WS_EX_TRANSPARENT = 0x00000020\n\n        hwnd = window.winfo_id()\n        style = ctypes.windll.user32.GetWindowLongW(hwnd, GWL_EXSTYLE)\n        ctypes.windll.user32.SetWindowLongW(\n            hwnd, GWL_EXSTYLE, style | WS_EX_LAYERED | WS_EX_TRANSPARENT\n        )\n    except Exception:\n        pass\n\n\ndef _force_redraw(window: tk.Toplevel):\n    """레이어드(반투명) 창은 배경색만 바뀌면 자동으로 다시 그려지지 않는 경우가\n    있어서, 색을 바꾼 뒤 강제로 repaint 시킨다. 실패해도 무시한다."""\n    if sys.platform != "win32":\n        return\n    try:\n        import ctypes\n\n        RDW_INVALIDATE = 0x0001\n        RDW_ERASE = 0x0004\n        RDW_ALLCHILDREN = 0x0080\n        RDW_UPDATENOW = 0x0100\n\n        hwnd = window.winfo_id()\n        ctypes.windll.user32.RedrawWindow(\n            hwnd,\n            None,\n            None,\n            RDW_INVALIDATE | RDW_ERASE | RDW_ALLCHILDREN | RDW_UPDATENOW,\n        )\n    except Exception:\n        pass\n\n\ndef _make_circular(window: tk.Toplevel, size: int):\n    """윈도우 자체를 지름 size인 원 모양으로 잘라낸다. Tk의 -transparentcolor\n    (컬러키 투명) 방식보다 훨씬 안정적으로 동작한다."""\n    if sys.platform != "win32":\n        return\n    try:\n        import ctypes\n\n        hwnd = window.winfo_id()\n        hrgn = ctypes.windll.gdi32.CreateEllipticRgn(0, 0, size, size)\n        ctypes.windll.user32.SetWindowRgn(hwnd, hrgn, True)\n    except Exception:\n        pass\n\n\nclass SafetyWindow:\n    def __init__(self):\n        self._queue: "queue.Queue[str]" = queue.Queue()\n        self._state_queue: "queue.Queue[bool]" = queue.Queue()\n        self._root = None\n        self._text = None\n        self._indicator = None\n        self._indicator_canvas = None\n\n    def start(self):\n        """반드시 메인 스레드에서 호출 (tkinter 제약)."""\n        self._root = tk.Tk()\n        self._root.title("voice-typer 안전창")\n        self._root.geometry(config.SAFETY_WINDOW_GEOMETRY)\n        self._root.attributes("-topmost", True)\n\n        self._text = tk.Text(self._root, wrap="word", font=("Malgun Gothic", 12))\n        self._text.pack(fill="both", expand=True)\n        self._text.insert(\n            "end",\n            f"[voice-typer] 대기 중... {config.HOTKEY} 키를 눌러 녹음을 시작하세요.\\n"\n            "여기 적힌 내용은 전부 남아있으니, 커서가 없는 곳에서 말해도 안전합니다.\\n"\n            "이 창은 최소화해도 되고, 화면 구석의 작은 점으로 녹음 상태를 확인할 수 있습니다.\\n\\n",\n        )\n\n        if config.INDICATOR_ENABLED:\n            self._build_indicator()\n\n        self._poll()\n        self._root.mainloop()\n\n    def _build_indicator(self):\n        size = config.INDICATOR_SIZE\n        margin = config.INDICATOR_MARGIN\n\n        self._indicator = tk.Toplevel(self._root)\n        self._indicator.overrideredirect(True)\n        self._indicator.attributes("-topmost", True)\n        try:\n            self._indicator.attributes("-alpha", config.INDICATOR_OPACITY)\n        except tk.TclError:\n            pass  # 일부 환경에선 창 투명도 속성이 없을 수 있음 - 불투명하게 남음\n\n        screen_w = self._indicator.winfo_screenwidth()\n        screen_h = self._indicator.winfo_screenheight()\n        x, y = _corner_position(config.INDICATOR_CORNER, screen_w, screen_h, size, margin)\n        self._indicator.geometry(f"{size}x{size}+{x}+{y}")\n\n        self._indicator_canvas = tk.Canvas(\n            self._indicator,\n            width=size,\n            height=size,\n            bg=config.INDICATOR_COLOR_IDLE,\n            highlightthickness=0,\n        )\n        self._indicator_canvas.pack()\n\n        self._indicator.update_idletasks()\n        _make_circular(self._indicator, size)\n        _make_click_through(self._indicator)\n\n    def append(self, text: str):\n        """다른 스레드에서 호출해서 안전창에 한 줄 추가하기."""\n        self._queue.put(text)\n\n    def set_recording(self, is_recording: bool):\n        """다른 스레드에서 호출해서 표시등 색을 바꾸기."""\n        self._state_queue.put(is_recording)\n\n    def _poll(self):\n        try:\n            while True:\n                text = self._queue.get_nowait()\n                timestamp = time.strftime("%H:%M:%S")\n                self._text.insert("end", f"[{timestamp}] {text}\\n")\n                self._text.see("end")\n        except queue.Empty:\n            pass\n\n        try:\n            while True:\n                is_recording = self._state_queue.get_nowait()\n                if self._indicator_canvas is not None:\n                    color = (\n                        config.INDICATOR_COLOR_RECORDING\n                        if is_recording\n                        else config.INDICATOR_COLOR_IDLE\n                    )\n                    self._indicator_canvas.configure(bg=color)\n                    self._indicator_canvas.update_idletasks()\n                    if self._indicator is not None:\n                        _force_redraw(self._indicator)\n        except queue.Empty:\n            pass\n\n        if self._root is not None:\n            self._root.after(100, self._poll)\n\n\ndef _corner_position(corner: str, screen_w: int, screen_h: int, size: int, margin: int):\n    if corner == "top-left":\n        return margin, margin\n    if corner == "bottom-left":\n        return margin, screen_h - size - margin\n    if corner == "bottom-right":\n        return screen_w - size - margin, screen_h - size - margin\n    return screen_w - size - margin, margin  # top-right\n'

FILES['voice_typer.py'] = '"""voice-typer: F2로 켜고 끄는 음성 타이핑 시스템.\n\n동작:\n  1. F2를 누르면 녹음 시작, 다시 누르면 녹음 종료 (config.MODE == "toggle").\n     또는 F2로 "상시 감지 모드" on/off, 그 안에서는 소리 크기로 자동 문장 구분\n     (config.MODE == "vad").\n  2. 녹음이 끝난 구간을 faster-whisper(turbo, GPU)로 텍스트 변환.\n  3. 변환된 텍스트를 (a) 현재 커서/포커스가 있는 곳에 실제로 타이핑하고,\n     (b) 항상 떠 있는 안전창(overlay)에도 남긴다. 커서가 없어서 (a)가\n     실패해도 (b) 덕분에 텍스트가 사라지지 않는다.\n\n오디오 입력은 sounddevice(PortAudio)가 아니라 soundcard(WASAPI) 라이브러리를\n쓴다. PortAudio는 초기화할 때 WDM-KS 등 모든 오디오 백엔드의 장치를 훑는데,\n일부 다채널 오디오 인터페이스(예: Antelope ZenGo SC) 드라이버에서 이 과정이\n그대로 프로세스를 죽여버리는 문제가 있었다. soundcard는 WASAPI만 쓰기 때문에\n이 문제를 피해간다 (Premiere Pro 등 일반 프로그램도 WASAPI/ASIO로 접근해서\n문제없이 녹음되는 것과 같은 이유).\n\n주의: GPU(NVIDIA, VRAM 8GB+)와 마이크가 있는 실제 PC에서 실행해야 한다.\n      이 코드는 개발 환경(원격 리눅스 샌드박스, GPU/마이크 없음)에서\n      문법 확인만 했고, 실제 녹음·GPU 추론·전역 단축키 동작은 검증하지\n      못했다. 로컬에서 처음 실행할 때는 README의 점검 순서를 따라\n      단계별로 확인할 것.\n"""\n\nimport os\nimport sys\nimport threading\n\n\ndef _register_nvidia_dll_dirs():\n    """pip로 설치된 nvidia-* 패키지(cublas, cudnn, cuda_nvrtc 등)의 DLL 폴더를\n    이 프로세스가 찾을 수 있게 등록한다. faster_whisper를 import하기 전에 실행해야 한다.\n\n    두 가지 방법을 모두 쓴다:\n      1) os.add_dll_directory  - 파이썬 확장 모듈(.pyd) 로딩용 표준 방식.\n      2) os.environ[\'PATH\'] 앞에 직접 추가 - ctranslate2는 cublas64_12.dll을\n         실행 도중 옛날 방식(LoadLibrary)으로 부르는데, 이건 add_dll_directory로\n         추가한 경로를 참조하지 않는다. 그래서 PATH에도 직접 넣어야 확실히 찾는다.\n         (예전에 \'set PATH=...\'를 손으로 했을 때만 됐던 이유가 이것이다.)\n    """\n    if sys.platform != "win32":\n        return\n    try:\n        import nvidia\n    except ImportError:\n        return\n\n    bin_dirs = []\n    for base in list(getattr(nvidia, "__path__", [])):\n        if not os.path.isdir(base):\n            continue\n        for sub in os.listdir(base):  # cublas, cudnn, cuda_nvrtc, ...\n            bin_dir = os.path.join(base, sub, "bin")\n            if os.path.isdir(bin_dir):\n                bin_dirs.append(bin_dir)\n\n    for bin_dir in bin_dirs:\n        try:\n            os.add_dll_directory(bin_dir)\n        except OSError:\n            pass\n    if bin_dirs:\n        os.environ["PATH"] = os.pathsep.join(bin_dirs) + os.pathsep + os.environ.get("PATH", "")\n\n\n_register_nvidia_dll_dirs()\n\nimport numpy as np\nimport soundcard as sc\nimport keyboard\nfrom faster_whisper import WhisperModel\n\nimport config\nfrom overlay import SafetyWindow\n\n\ndef rms_dbfs(block: np.ndarray) -> float:\n    """float32 [-1, 1] 오디오 블록의 대략적인 dBFS(RMS 기준) 값."""\n    rms = np.sqrt(np.mean(np.square(block)) + 1e-12)\n    return 20 * np.log10(rms + 1e-12)\n\n\ndef pick_microphone(safety_window: SafetyWindow):\n    """config.MIC_NAME과 이름이 겹치는 마이크를 고르고, 없으면 시스템 기본 마이크."""\n    if config.MIC_NAME:\n        try:\n            mic = sc.get_microphone(config.MIC_NAME, include_loopback=False)\n            safety_window.append(f"[마이크 선택] {mic.name}")\n            return mic\n        except Exception as exc:\n            safety_window.append(\n                f"[마이크 \'{config.MIC_NAME}\'을 못 찾음: {exc} - 기본 마이크로 대체]"\n            )\n    mic = sc.default_microphone()\n    safety_window.append(f"[마이크 선택 - 기본값] {mic.name}")\n    return mic\n\n\nclass VoiceTyper:\n    def __init__(self, safety_window: SafetyWindow):\n        self.safety_window = safety_window\n\n        self.mic = pick_microphone(safety_window)\n\n        self.safety_window.append(f"[모델 로딩 중] {config.MODEL_SIZE} / {config.DEVICE}")\n        self.model = WhisperModel(\n            config.MODEL_SIZE,\n            device=config.DEVICE,\n            compute_type=config.COMPUTE_TYPE,\n        )\n        self.safety_window.append("[모델 로딩 완료] F2를 눌러 녹음을 시작하세요.")\n\n        self.recording = False\n        self._frames: list[np.ndarray] = []\n        self._lock = threading.Lock()\n        self._stop_event: threading.Event | None = None\n        self._record_thread: threading.Thread | None = None\n\n    # ---------------- 공통: 녹음 -> 변환 -> 출력 ----------------\n\n    def _transcribe_and_emit(self, audio: np.ndarray):\n        if audio.size == 0:\n            return\n        duration = audio.size / config.SAMPLE_RATE\n        if duration < 0.2:\n            return  # 너무 짧은 잡음성 구간은 무시\n\n        segments, _info = self.model.transcribe(\n            audio,\n            language=config.LANGUAGE,\n            vad_filter=True,\n        )\n        text = "".join(seg.text for seg in segments).strip()\n        if not text:\n            self.safety_window.append("[인식된 말이 없음]")\n            return\n\n        self.safety_window.append(text)\n        if config.TYPE_AT_CURSOR:\n            try:\n                keyboard.write(text + " ")\n            except Exception as exc:  # 타이핑 실패해도 안전창엔 이미 남아있음\n                self.safety_window.append(f"[타이핑 실패: {exc}]")\n\n    def _run_transcription_async(self, audio: np.ndarray):\n        threading.Thread(target=self._transcribe_and_emit, args=(audio,), daemon=True).start()\n\n    # ---------------- MODE == "toggle" ----------------\n\n    def _record_loop(self, stop_event: threading.Event):\n        block_size = int(config.SAMPLE_RATE * 0.05)  # 50ms 씩 읽음\n        with self.mic.recorder(samplerate=config.SAMPLE_RATE, channels=1) as rec:\n            while not stop_event.is_set():\n                data = rec.record(numframes=block_size)\n                with self._lock:\n                    self._frames.append(data.reshape(-1).astype("float32"))\n\n    def toggle_recording(self):\n        with self._lock:\n            starting = not self.recording\n            self.recording = starting\n\n        if starting:\n            self._frames = []\n            self._stop_event = threading.Event()\n            self._record_thread = threading.Thread(\n                target=self._record_loop, args=(self._stop_event,), daemon=True\n            )\n            self._record_thread.start()\n            self.safety_window.append("[녹음 시작]")\n            self.safety_window.set_recording(True)\n        else:\n            self._stop_event.set()\n            self._record_thread.join(timeout=5)\n            self.safety_window.append("[녹음 종료 - 변환 중...]")\n            self.safety_window.set_recording(False)\n            with self._lock:\n                audio = np.concatenate(self._frames) if self._frames else np.array([], dtype="float32")\n                self._frames = []\n            self._run_transcription_async(audio)\n\n    # ---------------- MODE == "vad" ----------------\n\n    def _vad_loop(self, stop_event: threading.Event):\n        block_size = int(config.SAMPLE_RATE * config.VAD_BLOCK_MS / 1000)\n        speaking = False\n        silence_ms = 0\n        buffer: list[np.ndarray] = []\n\n        with self.mic.recorder(samplerate=config.SAMPLE_RATE, channels=1) as rec:\n            while not stop_event.is_set():\n                data = rec.record(numframes=block_size)\n                block = data.reshape(-1).astype("float32")\n                level = rms_dbfs(block)\n\n                if level >= config.VAD_DB_THRESHOLD:\n                    if not speaking:\n                        speaking = True\n                        self.safety_window.append("[말 시작 감지]")\n                        self.safety_window.set_recording(True)\n                    buffer.append(block)\n                    silence_ms = 0\n                elif speaking:\n                    buffer.append(block)\n                    silence_ms += config.VAD_BLOCK_MS\n                    if silence_ms >= config.VAD_SILENCE_MS:\n                        audio = np.concatenate(buffer)\n                        buffer = []\n                        speaking = False\n                        silence_ms = 0\n                        self.safety_window.append("[문장 종료 - 변환 중...]")\n                        self.safety_window.set_recording(False)\n                        self._run_transcription_async(audio)\n\n    def toggle_vad(self):\n        with self._lock:\n            starting = not self.recording\n            self.recording = starting\n\n        if starting:\n            self._stop_event = threading.Event()\n            self._record_thread = threading.Thread(\n                target=self._vad_loop, args=(self._stop_event,), daemon=True\n            )\n            self._record_thread.start()\n            self.safety_window.append(\n                f"[상시 감지 모드 ON] 기준 {config.VAD_DB_THRESHOLD} dBFS"\n            )\n        else:\n            self._stop_event.set()\n            self._record_thread.join(timeout=2)\n            self.safety_window.append("[상시 감지 모드 OFF]")\n            self.safety_window.set_recording(False)\n\n\ndef main():\n    safety_window = SafetyWindow()\n\n    # 모델 로딩과 녹음 관련 객체 생성은 tkinter 창이 뜬 뒤 별도 스레드에서 진행해야\n    # 무거운 모델 로딩 중에도 창이 멈춘 것처럼 보이지 않는다.\n    def setup_and_bind():\n        typer = VoiceTyper(safety_window)\n\n        if config.MODE == "toggle":\n            keyboard.add_hotkey(config.HOTKEY, typer.toggle_recording, suppress=config.SUPPRESS_HOTKEY)\n        elif config.MODE == "vad":\n            keyboard.add_hotkey(config.HOTKEY, typer.toggle_vad, suppress=config.SUPPRESS_HOTKEY)\n        else:\n            print(f"알 수 없는 MODE: {config.MODE}", file=sys.stderr)\n            sys.exit(1)\n\n    threading.Thread(target=setup_and_bind, daemon=True).start()\n\n    safety_window.start()  # 메인 스레드에서 tkinter mainloop 실행 (블로킹)\n\n\nif __name__ == "__main__":\n    main()\n'


def main():
    for name, content in FILES.items():
        path = HERE / name
        path.write_text(content, encoding="utf-8")
        print(f"[OK] {name} update done ({len(content)} bytes)")
    print()
    print("All files updated to the latest version. Now run run_voice_typer.")


if __name__ == "__main__":
    main()
